// Module declarations for static asset imports handled by Metro/Expo.
declare module "*.ttf" {
  const src: number;
  export default src;
}

declare module "*.otf" {
  const src: number;
  export default src;
}

declare module "*.png" {
  const src: number;
  export default src;
}

declare module "*.jpg" {
  const src: number;
  export default src;
}

declare module "*.jpeg" {
  const src: number;
  export default src;
}

declare module "*.svg" {
  const src: number;
  export default src;
}
